def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        reward = 0.0
        decay = 1.0
        growth = 1.0
        for j in range(1, 15):
            if j % 5 == 0:
                decay *= 0.85
                growth *= 1.05
            if ratio < (0.03 * j):
                score += (j ** 2) * (1 - ratio)**3 * decay
                if cap % (j + 2) == 0:
                    score += np.log1p(j) * growth
                else:
                    penalty += np.sqrt(j) / (ratio + 0.1)
            else:
                score += j * np.exp(-ratio * j * 1.1) * decay / (j + 2)
                if (cap * j) % 4 == 0:
                    reward += np.sin(ratio * j * 1.2) * growth
                else:
                    penalty += np.cos(ratio * j * 0.9)
            if j % 3 == 0:
                penalty += np.tanh(penalty / (j + 1))
            else:
                reward += np.arctan(reward / (j + 1))
        additive = 0.0
        multiplicative = 1.0
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    additive += np.log1p(residual) / (k + 0.7)
                    multiplicative *= (1 + residual/(cap+k))
                else:
                    penalty += (residual ** 0.3) / (k + 2.0)
                    multiplicative *= (1 - residual/(cap+1))
            else:
                penalty += abs(residual) * 0.2 * k
                multiplicative *= 0.9
            if k % 2 == 0:
                additive -= np.exp(-residual ** 2 / (k + 1))
            else:
                additive += np.exp(-residual / (k + 1))
        final_score = (score + additive + reward - penalty) * multiplicative / (cap + 2)
        if final_score > 0:
            priorities[i] = -final_score * np.exp(-ratio * 1.2)
        else:
            factor = np.log1p(cap) + np.sqrt(item) + 1
            priorities[i] = -final_score * factor / (1 + ratio)
    return priorities
